import Image from 'next/image'

export default function OptimizedImage({ src, alt, className }: {
  src: string
  alt: string
  className?: string
}) {
  return (
    <Image
      src={src}
      alt={alt}
      fill
      className={className}
      loading="lazy"
      quality={75}
      placeholder="blur"
      blurDataURL="data:image/jpeg;base64,"
    />
  )
}
